// ===============================================
//     🎯 ГЛАВНАЯ КОНФИГУРАЦИЯ AUTODOCK
//     Все настройки системы в одном месте
// ===============================================

// ========== 1. НАЗВАНИЯ ЛИСТОВ ==========
const SHEETS = {
