// ========== 2. НАЗВАНИЯ СТОЛБЦОВ ==========
const COLUMNS = {
  // === ОБЩИЕ ДЛЯ ОБОИХ ЛИСТОВ ===
  ID: "ID",
  FULL_NAME: "Фамилия Имя Отчество",

  // === СТОЛБЦЫ РЕЕСТРА ЗАЯВОК ===
  REGISTRY: {
