    FOLDER_LINK: "Ссылка на готовые макеты",  // Переименовали
    HASH_DATA: "Хеш данных",  // Переименовали
    LAST_UPDATE: "Дата последнего изменения"
  },

  // === СТОЛБЦЫ МАКЕТОВ ДОКУМЕНТОВ ===
  LAYOUTS: {
    CHECKBOX: "Чекбокс",  // Добавили
    SCENARIO: "Сценарий",
    DOCUMENT_TYPE: "Документ",
