  // === СТОЛБЦЫ ЛИСТА ШАБЛОНЫ ===
  TEMPLATES: {
    SCENARIO: "Сценарий",
    DOCUMENT: "Документ",
    TYPE: "Тип",  // docs или sheets
    FORMAT: "Формат",  // с подложкой/без подложки
    TEMPLATE_LINK: "Ссылка на шаблон"
  }

};

// ========== 3. ОБЯЗАТЕЛЬНЫЕ ПОЛЯ ==========
const REQUIRED_FIELDS = {
  // Базовые - для ВСЕХ документов
  base: [
    "Фамилия Имя Отчество",
    "Фамилия Имя Отчество в склонении",
    "Программа",
    "Часы",
    "Сценарий",
    "Документ об образовании"
  ],

  // Дополнительные для диплома с квалификацией
  diploma_qualified: [
    "Квалификация"
  ],

  // Для ФИС ФРДО (будет позже)
  fis_frdo: [
    "СНИЛС",
    "Дата рождения получателя",
    "Пол получателя"
  ]
};

// ========== 4. ДОПУСТИМЫЕ ЧАСЫ ==========
const VALID_HOURS = [
  16, 36, 72, 144, 256, 512, 520, 576, 720, 800, 1000, 1600, 2000
];

// Добавьте в конфигурацию
const STATUSES = {
  REGISTRY: {
    EMPTY: "",
    INCOMPLETE: "Неполные данные",
    READY: "Готов к обработке",
    IN_LAYOUTS: "Передано в макеты",
    NEEDS_REWORK: "Требует правок",
    DOCUMENTS_READY: "Документы готовы",
    READY_FOR_FIS: "Готов к подаче в ФИС ФРДО",
    IN_FIS_BATCH: "В пакете ФИС ФРДО",
    SUBMITTED_TO_FIS: "Подано в ФИС ФРДО",
    ISSUED: "Выдано",
    SENT_BY_MAIL: "Отправлено почтой",
    URGENT: "🔴 СРОЧНО"
  },

  LAYOUTS: {
    WAITING: "Ожидает генерации",
    URGENT: "🔴 СРОЧНО",
    IN_QUEUE: "В очереди",
    NEEDS_REWORK: "Требует правок",
    CREATED: "Макет создан",
    ERROR: "Ошибка генерации"
  }
};


// ========== 6. СЦЕНАРИИ И ПАКЕТЫ ==========
const SCENARIOS = {
  "Удостоверение": {
    documents: ["Удостоверение"],
    count: 1
  },
  "Диплом простой": {
    documents: ["Диплом простой", "Приложение к диплому", "Диплом на подложке"],
    count: 3
  },
  "Диплом с квалификацией": {
    documents: ["Диплом с квалификацией", "Приложение к диплому", "Диплом на подложке", "Выписка"],
    count: 4
  },
  "Охрана труда": {
    documents: ["Удостоверение ОТ", "Выписка"],
    count: 2
  },
  "Рабочие специальности": {
    documents: ["Удостоверение РС", "Свидетельство", "Выписка"],
    count: 3
  }
};

// ========== 7. СЧЕТЧИК ID (ИЗМЕНЕНО) ==========
// В N8n счетчик обрабатываем отдельно
function getNextId(currentId) {
  const nextNumber = (currentId || 0) + 1;
  return `REQ-${String(nextNumber).padStart(5, '0')}`;
}

// ========== 8. СОТРУДНИКИ ==========
const EMPLOYEES = {
  "Полянская М.В.": {
    telegramId: 123456789,
    folderId: "1RuDqHlHDfU5aChhpv1r4zNQRDIzzBh4K"
  }
};

// ========== 9. ФУНКЦИИ ДЛЯ РАБОТЫ С СОТРУДНИКАМИ ==========
function getEmployeeByName(name) {
  if (EMPLOYEES[name]) {
    return {
      name: name,
      ...EMPLOYEES[name]
    };
  }
  return null;
}

// ===============================================
//     📋 МАППИНГ ПОЛЕЙ И ПЕРЕМЕННЫХ
//     Соответствие полей таблицы и переменных в шаблонах
// ===============================================

const FIELD_MAPPING = {
  // ========== ХРАНИМЫЕ В РЕЕСТРЕ ==========
  stored: {
    "Фамилия Имя Отчество": {
      source: "Реестр",
      provides: {
        "<<Фамилия>>": "split()[0]",
        "<<Имя>>": "split()[1]",
        "<<Отчество>>": "split()[2]"
      }
    },

    "Фамилия Имя Отчество в склонении": {
      source: "Реестр",
      provides: {
        "<<Фамилия получателя>>": "split()[0]",
        "<<Имя получателя>>": "split()[1]",
        "<<Отчество получателя>>": "split()[2]"
      }
    },

    "СНИЛС": "<<СНИЛС>>",
    "Город не Москва": "<<Город>>",
    "Программа": "<<Программа>>",
    "Квалификация": "<<Квалификация>>",
    "Специализация": "<<Специализация>>",
    "Часы": "<<Часов>>",
    "Документ об образовании": "<<Документ об образовании>>",
    "Дата рождения получателя": "системное поле для ФИС ФРДО",
    "Пол получателя": "системное поле для ФИС ФРДО"
  },

  // ========== ВЫЧИСЛЯЕМЫЕ ПОЛЯ ==========
  computed: {
    "ID": {
      variable: "<<ID>>",
      generator: "getNextId()"
    },

    "Дата выдачи": {
      variable: "<<Дата>>",
      formula: "formatDate(issueDate)"
    },

    "Окончание обучения": {
      variable: "<<Окончание обучения>>",
      formula: "calculateStudyPeriod().endDate"
    },

    "Период обучения (компоненты)": {
      source: "calculateStudyPeriod()",
      provides: {
        "<<Число от>>": "startDay",
        "<<Месяц от>>": "startMonth",
        "<<Число до>>": "endDay",
        "<<Месяц до>>": "endMonth"
      }
    },

    // Регистрационные номера - для каждого типа своя переменная
    "Регистрационные номера": {
      "Удостоверение": "<<Рег-УПК>>",
      "Диплом простой": "<<Рег-ПП>>",
      "Диплом с квалификацией": "<<Рег-ПП>>",
      "Удостоверение ОТ": "<<Рег-ОТ>>",
      "Свидетельство": "<<Рег-РС-Н>>",
      "Удостоверение РС": "<<Рег-РС-АН>>"
    }
  }
};

// Функция получения переменной регномера для документа
function getRegVariable(documentType) {
  return FIELD_MAPPING.computed["Регистрационные номера"][documentType] || "<<Рег-УПК>>";
}

// ===============================================
//     📋 ГЕНЕРАТОР РЕГИСТРАЦИОННЫХ НОМЕРОВ
//     Форматы и логика генерации
// ===============================================

// ========== СЛОВАРЬ ФОРМАТОВ ==========
const REG_NUMBER_FORMATS = {
  "Удостоверение": {
    prefix: "ПК",
    format: "{number}-{month}/{prefix}",
    counter_name: "upk_counter",
    startFrom: 730
  },
  "Диплом простой": {
    prefix: "П",
    format: "{number}-{yy}{month}{prefix}",
    counter_name: "diploma_counter",
    startFrom: 770
  },
  "Диплом с квалификацией": {
    prefix: "П",
    format: "{number}-{yy}{month}{prefix}",
    counter_name: "diploma_counter",
    startFrom: 770
  },
  "Удостоверение ОТ": {
    prefix: "",
    format: "{month}{yy}-{number}",
    counter_name: "ot_counter",
    startFrom: 189
  },
  "Свидетельство": {
    prefix: "Н",
    format: "{number}-{prefix}",
    counter_name: "rs_counter",
    startFrom: 24216,
    sameNumber: true  // ВАЖНО: используем тот же номер!
  },
  "Удостоверение РС": {
    prefix: "АН",
    format: "{number}-{prefix}",
    counter_name: "rs_counter",
    startFrom: 24216,
    sameNumber: true  // ВАЖНО: используем тот же номер!
  }
};

// АДАПТИРОВАННАЯ функция для N8n
function generateRegNumber(documentType, staticData, packageId) {
  const config = REG_NUMBER_FORMATS[documentType];

  if (!config) {
    return "000-00";  // Дефолтный номер
  }

  // Инициализация счетчиков если их нет
  if (!staticData.regCounters) {
    staticData.regCounters = {
      upk_counter: 730,
      diploma_counter: 770,
      ot_counter: 189,
      rs_counter: 24216,
      last_rs_number: null
    };
  }

  let currentNumber;

  // Особая логика для РС документов
  if (config.sameNumber && packageId) {
    if (staticData.currentPackage === packageId && 
        staticData.regCounters.last_rs_number) {
      currentNumber = staticData.regCounters.last_rs_number;
    } else {
      currentNumber = ++staticData.regCounters[config.counter_name];
      staticData.regCounters.last_rs_number = currentNumber;
      staticData.currentPackage = packageId;
    }
  } else {
    currentNumber = ++staticData.regCounters[config.counter_name];
  }

  // Форматирование
  const now = new Date();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const yy = String(now.getFullYear()).slice(-2);

  return config.format
    .replace('{number}', currentNumber)
    .replace('{prefix}', config.prefix)
    .replace('{yy}', yy)
    .replace('{month}', month);
}

// Удалите текущий return и замените на:
return [{
  json: {
    config: {
      SHEETS,
      COLUMNS,
      REQUIRED_FIELDS,
      VALID_HOURS,
      STATUSES,
      SCENARIOS,
      EMPLOYEES,
      FIELD_MAPPING,
      REG_NUMBER_FORMATS
    },
    functions: {
      getNextId,
      getEmployeeByName,
      getRegVariable,
      generateRegNumber  // ДОБАВИЛИ
    }
  }
}];

// ===============================================
//     НОДА 4: ПРОВЕРКА СТРОК И ПРИСВОЕНИЕ ID
// ===============================================

// Получаем конфигурацию из ноды 2
const config = $('config').first().json.config;

// Получаем все строки из Google Sheets (нода 3)
const allRows = $input.all();

// РАБОТА СО СЧЕТЧИКОМ ID
let staticData = $getWorkflowStaticData('global');
if (!staticData.lastId) {
  staticData.lastId = 0;  // Начинаем с 0 если первый запуск
}

// Результат для обработки
const toProcess = [];

// Проверяем каждую строку
allRows.forEach((item, index) => {
  const row = item.json;
  const rowNumber = index + 2; // +2 т.к. первая строка - заголовки

  // Пропускаем если уже есть ID
  if (row[config.COLUMNS.ID] && row[config.COLUMNS.ID].toString().trim() !== '') {
    return;
  }

  // Проверяем обязательные поля
  const missing = [];
  config.REQUIRED_FIELDS.base.forEach(field => {
    if (!row[field] || row[field].toString().trim() === '') {
      missing.push(field);
    }
  });

  // Дополнительная проверка для диплома с квалификацией
  if (row[config.COLUMNS.REGISTRY.SCENARIO] === 'Диплом с квалификацией') {
    if (!row[config.COLUMNS.REGISTRY.QUALIFICATION] || 
        row[config.COLUMNS.REGISTRY.QUALIFICATION].trim() === '') {
      missing.push('Квалификация');
    }
  }

  // Если все поля заполнены - ПРИСВАИВАЕМ ID
  if (missing.length === 0) {
    // ГЕНЕРИРУЕМ НОВЫЙ ID
    staticData.lastId++;  // Увеличиваем счетчик
    const newId = `REQ-${String(staticData.lastId).padStart(5, '0')}`;

    toProcess.push({
      json: {
        rowNumber: rowNumber,
        action: 'assign_id',
        newId: newId,
        fullName: row[config.COLUMNS.FULL_NAME],
        scenario: row[config.COLUMNS.REGISTRY.SCENARIO],
        updates: {
          [config.COLUMNS.ID]: newId,
          [config.COLUMNS.REGISTRY.STATUS]: config.STATUSES.REGISTRY.READY,
          [config.COLUMNS.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU')
        }
      }
    });

  } else {
    // Есть пустые поля
    toProcess.push({
      json: {
        rowNumber: rowNumber,
        action: 'incomplete',
        updates: {
          [config.COLUMNS.REGISTRY.STATUS]: config.STATUSES.REGISTRY.INCOMPLETE,
          [config.COLUMNS.REGISTRY.LAST_UPDATE]: `Не заполнены: ${missing.join(', ')}`
        }
      }
    });
  }
});

// СОХРАНЯЕМ СЧЕТЧИК для следующего запуска
$getWorkflowStaticData('global').lastId = staticData.lastId;

return toProcess;

// Функция для извлечения текста из одной ячейки таблицы
function extractCellText(cell) {
  if (!cell || !cell.content) return '';

  let text = '';
  for (const element of cell.content) {
    if (element.paragraph && element.paragraph.elements) {
      for (const paragraphElement of element.paragraph.elements) {
        if (paragraphElement.textRun && paragraphElement.textRun.content) {
          text += paragraphElement.textRun.content;
        }
      }
    }
  }

  return text.trim();
}

// Функция для извлечения данных из одной таблицы
function extractTableData(table) {
  if (!table || !table.tableRows) return [];

  const tableData = [];

  for (const row of table.tableRows) {
    const rowData = [];

    if (row.tableCells) {
      for (const cell of row.tableCells) {
        const cellText = extractCellText(cell);
        rowData.push(cellText);
      }
    }

    tableData.push(rowData);
  }

  return tableData;
}

// Функция для обработки одного документа
function processDocument(doc) {
  const tables = [];

  if (!doc.body || !doc.body.content) {
    return tables;
  }

  for (const element of doc.body.content) {
    if (element.table) {
      const tableData = extractTableData(element.table);
      tables.push({
        documentId: doc.documentId || 'unknown',
        documentTitle: doc.title || 'untitled',
        tableIndex: tables.length,
        rowCount: tableData.length,
        columnCount: tableData.length > 0 ? tableData[0].length : 0,
        data: tableData
      });
    }
  }

  return tables;
}

// Основной код для n8n
const inputItems = $input.all();
const outputItems = [];

for (const item of inputItems) {
  const doc = item.json;

  // Обрабатываем документ
  const tables = processDocument(doc);

  // Создаём отдельный выходной элемент для каждой таблицы
  for (const table of tables) {
    outputItems.push({
      json: {
        documentId: table.documentId,
        documentTitle: table.documentTitle,
        tableIndex: table.tableIndex,
        rowCount: table.rowCount,
        columnCount: table.columnCount,
        tableData: table.data,
        // Дополнительно: плоский массив всех ячеек
        allCells: table.data.flat(),
        // Дополнительно: первая строка как заголовки
        headers: table.data.length > 0 ? table.data[0] : [],
        // Дополнительно: данные без первой строки
        rows: table.data.length > 1 ? table.data.slice(1) : []
      }
    });
  }
}

return outputItems;

const all_docs = $('Code in JavaScript').all();
const res = [];

all_docs.forEach(item => {
  // Проверяем, что tableData есть и содержит хотя бы 9 таблиц (8-я = индекс 8)
  if (item.json.tableData && item.json.tableData.length > 8) {
    const table8 = item.json.tableData[8];

    // Убираем пустые значения
    const flatData = (table8 || []).filter(v => v && v.trim() !== '');

    // Группируем по 3 элемента
    const dates = [];
    for (let i = 0; i < flatData.length; i += 3) {
      dates.push(flatData.slice(i, i + 3).join(' '));
    }

    res.push({ dates });
  } else {
    res.push({ dates: [] }); // если таблицы меньше 9, возвращаем пустой массив
  }
});

return res.map(r => ({ json: r }));

const doc = $('Get a document').all();
const content = doc.body?.content || [];

const tables = [];

for (const block of content) {
  if (block.table) {
    const table = block.table;
    const rows = [];

    for (const row of table.tableRows || []) {
      const cells = [];

      for (const cell of row.tableCells || []) {
        let text = '';

        for (const item of cell.content || []) {
          if (item.paragraph) {
            for (const el of item.paragraph.elements || []) {
              const run = el.textRun;
              if (run && run.content) {
                text += run.content;
              }
            }
          }
        }

        cells.push(text.trim());
      }

      rows.push(cells);
    }

    tables.push(rows);
  }
}

return tables.map(t => ({ json: { table: t } }));

const all_docs = $('Code in JavaScript3').all();
const res = [];

all_docs.forEach(item => {
  const tables = item.json.tables || [];

  if (tables.length > 1) { // проверяем, что есть хотя бы 2 таблицы
    const table2 = tables[1]; 

    if (table2.length > 6) { // проверяем, что есть 7-я строка (индекс 6)
      const row6 = table2[5] || [];

      // убираем пустые значения и лишние слова
      const dates = row6
        .filter(v => v && v.trim() !== '')
        .map(v => v
          .replace(/в период с/gi, '')
          .replace(/по/gi, '')
          .replace(/г\./gi, '')
          .replace(/«|»/g, '')
          .trim()
        );

      res.push({ dates });
    } else {
      res.push({ dates: [] }); // если строки меньше 7
    }
  } else {
    res.push({ dates: [] }); // если таблиц меньше 2
  }
});

return res.map(r => ({ json: r }));

