      for (const paragraphElement of element.paragraph.elements) {
        if (paragraphElement.textRun && paragraphElement.textRun.content) {
          text += paragraphElement.textRun.content;
        }
      }
    }
  }

  return text.trim();
}

// Функция для извлечения данных из одной таблицы
function extractTableData(table) {
  if (!table || !table.tableRows) return [];

  const tableData = [];

  for (const row of table.tableRows) {
    const rowData = [];

    if (row.tableCells) {
      for (const cell of row.tableCells) {
        const cellText = extractCellText(cell);
        rowData.push(cellText);
      }
    }

    tableData.push(rowData);
  }

  return tableData;
}

// Функция для обработки одного документа
function processDocument(doc) {
  const tables = [];

  if (!doc.body || !doc.body.content) {
    return tables;
  }

  for (const element of doc.body.content) {
    if (element.table) {
      const tableData = extractTableData(element.table);
      tables.push({
        documentId: doc.documentId || 'unknown',
        documentTitle: doc.title || 'untitled',
        tableIndex: tables.length,
        rowCount: tableData.length,
        columnCount: tableData.length > 0 ? tableData[0].length : 0,
        data: tableData
      });
    }
  }

  return tables;
}

// Основной код для n8n
const inputItems = $input.all();
const outputItems = [];

for (const item of inputItems) {
  const doc = item.json;

  // Обрабатываем документ
  const tables = processDocument(doc);

  // Создаём отдельный выходной элемент для каждой таблицы
  for (const table of tables) {
    outputItems.push({
      json: {
        documentId: table.documentId,
        documentTitle: table.documentTitle,
        tableIndex: table.tableIndex,
        rowCount: table.rowCount,
        columnCount: table.columnCount,
        tableData: table.data,
        // Дополнительно: плоский массив всех ячеек
        allCells: table.data.flat(),
        // Дополнительно: первая строка как заголовки
        headers: table.data.length > 0 ? table.data[0] : [],
        // Дополнительно: данные без первой строки
        rows: table.data.length > 1 ? table.data.slice(1) : []
      }
    });
  }
}

return outputItems;

