    const dates = [];
    for (let i = 0; i < flatData.length; i += 3) {
      dates.push(flatData.slice(i, i + 3).join(' '));
    }

    res.push({ dates });
  } else {
    res.push({ dates: [] }); // если таблицы меньше 9, возвращаем пустой массив
  }
});

