if (!table9) throw new Error("Таблица с 9 колонками не найдена");

for (const row of table9.table.tableRows) {
  const cells = row.tableCells;
  const nameText = cells[1]?.content
    ?.flatMap(p => p.paragraph?.elements ?? [])
    ?.map(e => e.textRun?.content ?? "")
    ?.join("")
    ?.trim();

  if (nameText === targetName) {
     return [{ json: { insertIndex: cells[6].content[0].startIndex } }];;
  }
}

throw new Error(`ФИО "${targetName}" не найдено`);

const filials_dict = $('filials').first().json;
const reviews = $('reviews').all();
const result = [];

for (let review of reviews) {
  result.push({
    name: review.json.user.name,
    rate: review.json.rate,
    review_text: review.json.text,
    review_date: new Date(review.json.date * 1000).toISOString().slice(0,10),
    platform_name: filials_dict[review.json.platform].type,
    filial_link: filials_dict[review.json.platform].link,
    filial_name: filials_dict[review.json.platform].filials[0],
  })
}

return result;

const doc = $input.first().json;
const body = doc.body;
const documentId = doc.documentId;

const SCALE = 0.75;
const MIN_SIZE = 5;

const START_MARKER = 'Решением аттестационной комиссии';
const END_MARKER = 'Основание:';

const requests = [];

function findMarkerIndex(content, marker) {
  for (const element of content || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          const result = findMarkerIndex(cell.content, marker);
          if (result) return result;
        }
      }
    }
    if (element.paragraph) {
      const fullText = element.paragraph.elements
        .map(pe => pe.textRun?.content || '')
        .join('');

      if (fullText.includes(marker)) {
        const elements = element.paragraph.elements;
        const lastEl = elements[elements.length - 1];
        return {
          startIndex: elements[0].startIndex,
          endIndex: lastEl.endIndex
        };
      }
    }
  }
  return null;
}

function processContent(content, rangeStart, rangeEnd) {
  for (const element of content || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          processContent(cell.content, rangeStart, rangeEnd);
        }
      }
    }
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        if (!pe.textRun) continue;

        const currentSize = pe.textRun.textStyle?.fontSize?.magnitude;
        if (!currentSize) continue;

        // только элементы внутри диапазона
        if (pe.startIndex >= rangeStart && pe.endIndex <= rangeEnd) {
          const newSize = Math.max(Math.round(currentSize * SCALE), MIN_SIZE);

          requests.push({
            updateTextStyle: {
              range: {
                startIndex: pe.startIndex,
                endIndex: pe.endIndex
              },
              textStyle: {
                fontSize: {
                  magnitude: newSize,
                  unit: 'PT'
                }
              },
              fields: 'fontSize'
            }
          });
        }
      }
    }
  }
}

const startEl = findMarkerIndex(body.content, START_MARKER);
const endEl = findMarkerIndex(body.content, END_MARKER);

if (!startEl || !endEl) {
  throw new Error('Маркеры не найдены в документе');
}

processContent(body.content, startEl.endIndex, endEl.startIndex);

return [{
  json: {
    documentId,
    requests
  }
}];

const doc = $input.first().json;
const body = doc.body;
const documentId = doc.documentId;

const SCALE = 0.85;
const MIN_SIZE = 5;
const MIN_LENGTH = 160;
const MARKER = 'Протокол';

const requests = [];

function getCellText(cellContent) {
  let text = '';
  for (const element of cellContent || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          text += getCellText(cell.content);
        }
      }
    }
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        text += pe.textRun?.content || '';
      }
    }
  }
  return text;
}

function processCell(cellContent) {
  let markerStartIndex = null;

  for (const element of cellContent || []) {
    if (element.paragraph) {
      const fullText = element.paragraph.elements
        .map(pe => pe.textRun?.content || '')
        .join('');
      if (fullText.includes(MARKER)) {
        markerStartIndex = element.paragraph.elements[0].startIndex;
        break;
      }
    }
  }

  if (markerStartIndex === null) return;

  let rangeText = '';
  for (const element of cellContent || []) {
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        if (!pe.textRun) continue;
        if (pe.endIndex <= markerStartIndex) {
          rangeText += pe.textRun.content || '';
        }
      }
    }
  }

  const textLength = rangeText.replace(/\s/g, '').length;
  if (textLength < MIN_LENGTH) return;

  for (const element of cellContent || []) {
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        if (!pe.textRun) continue;
        const currentSize = pe.textRun.textStyle?.fontSize?.magnitude;
        if (!currentSize) continue;
        if (pe.endIndex <= markerStartIndex) {
          const newSize = Math.max(Math.round(currentSize * SCALE), MIN_SIZE);
          requests.push({
            updateTextStyle: {
              range: {
                startIndex: pe.startIndex,
                endIndex: pe.endIndex
              },
              textStyle: {
                fontSize: { magnitude: newSize, unit: 'PT' }
              },
              fields: 'fontSize'
            }
          });
        }
      }
    }
  }
}

function traverseContent(content) {
  for (const element of content || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          const cellText = getCellText(cell.content);
          if (cellText.includes(MARKER)) {
            processCell(cell.content);
          } else {
            traverseContent(cell.content);
          }
        }
      }
    }
  }
}

traverseContent(body.content);

if (requests.length === 0) {
  return [{ json: { documentId, requests: [] } }];
}

return [{
  json: {
    documentId,
    requests
  }
}];
